mapper.insert:
INSERT INTO plant (
  plantno, memberno, plant_name, plant_type, growth, last_access, plant_status
) VALUES (
  plant_seq.nextval, #{memberno}, #{plant_name}, #{plant_type}, 0, SYSDATE, '정상'
)

mapper.select:
SELECT * FROM plant
WHERE memberno = #{memberno}
ORDER BY plantno DESC

mapper.update:
UPDATE plant
SET growth = #{growth}, last_access = SYSDATE
WHERE plantno = #{plantno}

UPDATE plant
SET growth = CASE
  WHEN NVL(growth, 0) + #{amount} > 100 THEN 100
  ELSE NVL(growth, 0) + #{amount}
END
WHERE memberno = #{memberno}
